export const compile = async (source: string) => {
    const input = JSON.stringify({
        language: "Solidity",
        settings: {
            outputSelection: {
                "*": {
                    "*": ["abi", "evm.bytecode"],
                },
            },
        },
        sources: {
            "tmp.sol": {
                content: source,
            },
        },
    });
    const solcData = await solc.compile(input);
    const output = JSON.parse(solcData);
    if (!output["contracts"]) {
        console.log(output);
        throw Error("Could not compile contract");
    }
    const fileOutput = output["contracts"]["tmp.sol"];

    // Find the first contract with bytecode in the output, this allows the
    // compiled code to include interfaces.
    for (const contract in fileOutput) {
        const contractOutput = fileOutput[contract];
        if (!contractOutput["evm"]["bytecode"] || !contractOutput["evm"]["bytecode"]["object"]) {
            continue;
        }

        const abi = contractOutput["abi"];
        const data = "0x" + contractOutput["evm"]["bytecode"]["object"];
        return {
            data,
            interface: abi,
        };
    }

    console.log(output);
    throw Error("No contract with bytecode");
};

export const getContractStorageLayout = async (hre: HardhatRuntimeEnvironment, smartContractName: string) => {
    const { sourceName, contractName } = await hre.artifacts.readArtifact(smartContractName);

    const stateVariables: StateVariable[] = [];

    for (const artifactPath of await hre.artifacts.getBuildInfoPaths()) {
        const artifact = fs.readFileSync(artifactPath);
        const artifactJsonABI = JSON.parse(artifact.toString());

        const artifactIncludesStorageLayout = artifactJsonABI?.output?.contracts?.[sourceName]?.[contractName]?.storageLayout;
        if (!artifactIncludesStorageLayout) {
            continue;
        }

        const contractStateVariablesFromArtifact = artifactJsonABI.output.contracts[sourceName][contractName].storageLayout.storage;
        for (const stateVariable of contractStateVariablesFromArtifact) {
            stateVariables.push({
                name: stateVariable.label,
                slot: stateVariable.slot,
                offset: stateVariable.offset,
                type: stateVariable.type,
            });
        }

        // The same contract can be present in multiple artifacts; thus we break if we already got
        // storage layout once
        break;
    }

    return stateVariables;
};

function warnAboutUnusedLoadedPlugins(
  resolvedPlugins: HardhatPlugin[],
  printError: (message: string) => void = (message) => console.error(message),
  loadedPlugins: Iterable<HardhatPlugin> = getLoadedPlugins().values(),
): void {
  const resolvedIds = new Set(resolvedPlugins.map((p) => p.id));

  const unused: HardhatPlugin[] = [];
  for (const plugin of loadedPlugins) {
    if (!resolvedIds.has(plugin.id)) {
      unused.push(plugin);
    }
  }

  if (unused.length === 0) {
    return;
  }

  const lines: string[] = [
    "",
    styleText(["bold", "yellow"], "Warning:") +
      " the following plugins were imported but are not present in the `plugins` array of your config:",
    "",
  ];

  for (const plugin of unused) {
    const name =
      plugin.npmPackage !== undefined && plugin.npmPackage !== null
        ? `${plugin.npmPackage}  (id: ${plugin.id})`
        : plugin.id;
    lines.push(`  - ${name}`);
  }

  lines.push(
    "",
    "  Add them to the `plugins` array, or remove the unused plugin import(s) to silence this warning.",
    "",
  );

  printError(lines.join("\n"));
}

function collectValidationErrorsForUserConfig(
  config: HardhatUserConfig,
): HardhatUserConfigValidationError[] {
  const validationErrors: HardhatUserConfigValidationError[] = [];

  if (config.paths !== undefined) {
    if (isObject(config.paths)) {
      validationErrors.push(...validatePaths(config.paths));
    } else {
      validationErrors.push({
        path: ["paths"],
        message: "paths must be an object",
      });
    }
  }

  if (config.tasks !== undefined) {
    if (Array.isArray(config.tasks)) {
      validationErrors.push(...validateTasksConfig(config.tasks));
    } else {
      validationErrors.push({
        path: ["tasks"],
        message: "tasks must be an array",
      });
    }
  }

  if (config.plugins !== undefined) {
    if (Array.isArray(config.plugins)) {
      validationErrors.push(...validatePluginsConfig(config.plugins));
    } else {
      validationErrors.push({
        path: ["plugins"],
        message: "plugins must be an array",
      });
    }
  }

  return validationErrors;
}

function validatePaths(
  paths: ProjectPathsUserConfig,
): HardhatUserConfigValidationError[] {
  const validationErrors: HardhatUserConfigValidationError[] = [];

  if (paths.cache !== undefined) {
    validationErrors.push(...validatePath(paths.cache, "cache"));
  }

  if (paths.artifacts !== undefined) {
    validationErrors.push(...validatePath(paths.artifacts, "artifacts"));
  }

  if (paths.tests !== undefined) {
    // paths.tests of type TestPathsUserConfig is not validated because it is customizable by the user
    if (!isObject(paths.tests)) {
      validationErrors.push(...validatePath(paths.tests, "tests"));
    }
  }

  if (paths.sources !== undefined) {
    if (Array.isArray(paths.sources)) {
      for (const [index, source] of paths.sources.entries()) {
        validationErrors.push(...validatePath(source, "sources", index));
      }
      // paths.sources of type SourcePathsUserConfig is not validated because it is customizable by the user
    } else if (!isObject(paths.sources)) {
      validationErrors.push(...validatePath(paths.sources, "sources"));
    }
  }

  return validationErrors;
}

function validateNewTask(
  task: NewTaskDefinition,
  path: Array<string | number>,
  isPlugin: boolean = false,
): HardhatUserConfigValidationError[] {
  const validationErrors: HardhatUserConfigValidationError[] = [];

  if (
    !Array.isArray(task.id) ||
    !task.id.every((id) => typeof id === "string")
  ) {
    validationErrors.push({
      path: [...path, "id"],
      message: "task id must be an array of strings",
    });
  }

  if (typeof task.description !== "string") {
    validationErrors.push({
      path: [...path, "description"],
      message: "task description must be a string",
    });
  }

  validationErrors.push(...validateActionFields(task, path, isPlugin));

  if (isObject(task.options)) {
    validationErrors.push(
      ...validateOptions(task.options, [...path, "options"]),
    );
  } else {
    validationErrors.push({
      path: [...path, "options"],
      message: "task options must be an object",
    });
  }

  if (Array.isArray(task.positionalArguments)) {
    validationErrors.push(
      ...validatePositionalArguments(task.positionalArguments, path),
    );
  } else {
    validationErrors.push({
      path: [...path, "positionalArguments"],
      message: "task positionalArguments must be an array",
    });
  }

  return validationErrors;
}

