async function getBlockUtil(
    hre: HardhatRuntimeEnvironment,
    identifier?: BlockIdentifier
): Promise<Block> {
    const blockOptions = {
        feederGatewayUrl: hre.starknet.networkConfig.url,
        gatewayUrl: hre.starknet.networkConfig.url,
        number: identifier?.blockNumber,
        hash: identifier?.blockHash
    };

    if (identifier && typeof identifier !== "object") {
        const msg = `Invalid identifier provided to getBlock: ${identifier}`;
        throw new StarknetPluginError(msg);
    }

    if (blockOptions.number == null && !blockOptions.hash) {
        blockOptions.number = "latest";
    }

    const executed = await hre.starknetWrapper.getBlock(blockOptions);

    if (executed.statusCode) {
        const msg = `Could not get block. Error: ${executed.stderr.toString()}`;
        throw new StarknetPluginError(msg);
    }
    const block = JSON.parse(executed.stdout.toString()) as Block;
    return block;
}

private async getContractHash(
    paths: ProjectPathsConfig
): Promise<Record<string, ContractData>> {
    const { starknetSources: defaultSourcesPath } = paths;

    const sourceRegex = new RegExp("^" + defaultSourcesPath + "/");
    const artifactsDir = getArtifactPath(defaultSourcesPath, paths);

    const newCacheEntry: Record<string, ContractData> = {};
    // Get sources from source path. Check only cairo file extensions
    const filesList = await traverseFiles(defaultSourcesPath, "*.cairo");
    // Select file name
    for (const cairoContract of filesList) {
        const data = await this.cache.fsPromises.readFile(cairoContract);
        const hash = createHash("sha256");
        hash.update(data);
        const suffix = cairoContract.replace(sourceRegex, "");

        const fileName = path.basename(suffix, ".cairo");
        const abiPath = path.join(artifactsDir, suffix, `${fileName}${ABI_SUFFIX}`);
        const outputPath = path.join(artifactsDir, suffix, `${fileName}.json`);

        newCacheEntry[cairoContract] = {
            contentHash: hash.digest("hex").toString(),
            outputPath,
            abiPath
        };
    }

    return newCacheEntry;
}

public async runSequentialHandlers<
    HookCategoryNameT extends keyof HardhatHooks,
    HookNameT extends keyof HardhatHooks[HookCategoryNameT],
    HookT extends HardhatHooks[HookCategoryNameT][HookNameT],
  >(
    hookCategoryName: HookCategoryNameT,
    hookName: HookNameT,
    params: InitialHookParams<HookCategoryNameT, HookT>,
  ): Promise<
    Array<Awaited<Return<HardhatHooks[HookCategoryNameT][HookNameT]>>>
  > {
    const handlers = await this.#getHandlersInSequentialRunningOrder(
      hookCategoryName,
      hookName,
    );

    let handlerParams: any;
    if (hookCategoryName !== "config") {
      assertHardhatInvariant(
        this.#context !== undefined,
        "Context must be set before running non-config hooks",
      );

      handlerParams = [this.#context, ...params];
    } else {
      handlerParams = params;
    }

    const result = [];
    for (const handler of handlers) {
      result.push(await (handler as any)(...handlerParams));
    }

    return result;
  }

public async runParallelHandlers<
    HookCategoryNameT extends keyof HardhatHooks,
    HookNameT extends keyof HardhatHooks[HookCategoryNameT],
    HookT extends HardhatHooks[HookCategoryNameT][HookNameT],
  >(
    hookCategoryName: HookCategoryNameT,
    hookName: HookNameT,
    params: InitialHookParams<HookCategoryNameT, HookT>,
  ): Promise<
    Array<Awaited<Return<HardhatHooks[HookCategoryNameT][HookNameT]>>>
  > {
    // The ordering of handlers is unimportant here, as they are run in parallel
    const handlers = await this.#getHandlersInChainedRunningOrder(
      hookCategoryName,
      hookName,
    );

    let handlerParams: any;
    if (hookCategoryName !== "config") {
      assertHardhatInvariant(
        this.#context !== undefined,
        "Context must be set before running non-config hooks",
      );

      handlerParams = [this.#context, ...params];
    } else {
      handlerParams = params;
    }

    return await Promise.all(
      handlers.map((handler) => (handler as any)(...handlerParams)),
    );
  }

async #resolveImportAction(
  action: LazyActionObject<TaskOverrideActionFunction<TaskArguments>>,
  actionPluginId?: string,
): Promise<NewTaskActionFunction | TaskOverrideActionFunction> {
  let resolvedActionFn;
  try {
    resolvedActionFn = await action();
  } catch (error) {
    ensureError(error);

    if (actionPluginId !== undefined) {
      const plugin = this.#hre.config.plugins.find(
        (p) => p.id === actionPluginId,
      );

      assertHardhatInvariant(
        plugin !== undefined,
        `Plugin with id ${actionPluginId} not found.`,
      );

      await detectPluginNpmDependencyProblems(
        this.#hre.config.paths.root,
        plugin,
        error,
      );
    }

    throw new HardhatError(
      HardhatError.ERRORS.CORE.TASK_DEFINITIONS.INVALID_ACTION_IMPORT,
      {
        task: formatTaskId(this.id),
      },
      error,
    );
  }

  if (typeof resolvedActionFn.default !== "function") {
    throw new HardhatError(
      HardhatError.ERRORS.CORE.TASK_DEFINITIONS.INVALID_ACTION,
      {
        task: formatTaskId(this.id),
      },
    );
  }

  return resolvedActionFn.default;
}

#processTaskOverride(
  taskDefinition: TaskOverrideDefinition,
  pluginId?: string,
) {
  const task = this.getTask(taskDefinition.id);
  for (const [optionName, optionValue] of Object.entries(
    taskDefinition.options,
  )) {
    const hasArgument =
      task.options.has(optionName) ||
      task.positionalArguments.some((p) => p.name === optionName);
    if (hasArgument) {
      throw new HardhatError(
        HardhatError.ERRORS.CORE.TASK_DEFINITIONS.TASK_OVERRIDE_OPTION_ALREADY_DEFINED,
        {
          actorFragment: getActorFragment(pluginId),
          option: optionName,
          task: formatTaskId(taskDefinition.id),
        },
      );
    }

    task.options.set(optionName, optionValue);
  }

  if (taskDefinition.description !== undefined) {
    task.description = taskDefinition.description;
  }

  task.actions.push({
    pluginId,
    ...(taskDefinition.action !== undefined
      ? { action: taskDefinition.action }
      : { inlineAction: taskDefinition.inlineAction }),
  });
}

#validateTaskDefinition(
  taskDefinition: TaskDefinition,
  isPlugin: boolean,
): void {
  validateId(taskDefinition.id);

  // Empty tasks don't have actions, options, or positional arguments
  if (taskDefinition.type === TaskDefinitionType.EMPTY_TASK) {
    return;
  }

  validateAction(
    taskDefinition.action,
    taskDefinition.inlineAction,
    taskDefinition.id,
    isPlugin,
  );

  const usedNames = new Set<string>();

  Object.values(taskDefinition.options).forEach((optionDefinition) =>
    validateOption(optionDefinition, usedNames, taskDefinition.id),
  );

  // Override tasks don't have positional arguments
  if (taskDefinition.type === TaskDefinitionType.TASK_OVERRIDE) {
    return;
  }

  let lastArg: PositionalArgumentDefinition;
  taskDefinition.positionalArguments.forEach((posArgDefinition) => {
    validatePositionalArgument(
      posArgDefinition,
      usedNames,
      taskDefinition.id,
      lastArg,
    );
    lastArg = posArgDefinition;
  });
}

function validatePositionalArgument(
  { name, type, defaultValue, isVariadic }: PositionalArgumentDefinition,
  usedNames: Set<string>,
  taskId: string | string[],
  lastArg?: PositionalArgumentDefinition,
): void {
  validateArgumentName(name);

  if (usedNames.has(name)) {
    throw new HardhatError(HardhatError.ERRORS.CORE.ARGUMENTS.DUPLICATED_NAME, {
      name,
    });
  }

  if (defaultValue !== undefined) {
    validateTaskArgumentValue(
      "defaultValue",
      type,
      defaultValue,
      isVariadic,
      taskId,
    );
  }

  if (lastArg !== undefined && lastArg.isVariadic) {
    throw new HardhatError(
      HardhatError.ERRORS.CORE.TASK_DEFINITIONS.POSITIONAL_ARG_AFTER_VARIADIC,
      {
        name,
      },
    );
  }

  if (
    lastArg !== undefined &&
    !isArgumentRequired(lastArg.type, lastArg.defaultValue) &&
    isArgumentRequired(type, defaultValue)
  ) {
    throw new HardhatError(
      HardhatError.ERRORS.CORE.TASK_DEFINITIONS.REQUIRED_ARG_AFTER_OPTIONAL,
      {
        name,
      },
    );
  }

  usedNames.add(name);
}

fetchValue: async (
  context: HookContext,
  variable: ConfigurationVariable,
  next,
) => {
  // Environment variables should take precedence over keystore
  if (process.env[variable.name] !== undefined) {
    return await next(context, variable);
  }

  // If we are in CI, the keystore should not be used
  // or even initialized
  if (isCi()) {
    return await next(context, variable);
  }

  // First try to get the value from the development keystore
  let value = await getValue(context, variable, true);

  if (value !== undefined) {
    return value;
  }

  if (process.env.HH_TEST === "true") {
    // When `fetchValue` is called from a test, we only allow the use of the development keystore
    // to avoid prompting for the production keystore password.
    throw new HardhatError(
      HardhatError.ERRORS.HARDHAT_KEYSTORE.GENERAL.KEY_NOT_FOUND_DURING_TESTS_WITH_DEV_KEYSTORE,
      {
        key: variable.name,
      },
    );
  }

  // Then, if the development keystore does not have the key and `fetchValue` is not called from a test,
  // attempt to retrieve the value from the production keystore.
  value = await getValue(context, variable, false);

  if (value !== undefined) {
    return value;
  }

  return await next(context, variable);
}

function resolveEdrNetworkAccounts(
  accounts:
    | EdrNetworkAccountsUserConfig
    | undefined = DEFAULT_EDR_NETWORK_HD_ACCOUNTS_CONFIG_PARAMS,
  resolveConfigurationVariable: ConfigurationVariableResolver,
): EdrNetworkAccountsConfig {
  if (Array.isArray(accounts)) {
    return accounts.map(({ privateKey, balance }) => {
      if (typeof privateKey === "string") {
        privateKey = normalizeHexString(privateKey);
      }

      return {
        privateKey: resolveConfigurationVariable(privateKey),
        balance: BigInt(balance),
      };
    });
  }

  const {
    mnemonic: defaultMnemonic,
    accountsBalance: defaultAccountsBalance,
    passphrase: defaultPassphrase,
    ...defaultHdAccountRest
  } = DEFAULT_EDR_NETWORK_HD_ACCOUNTS_CONFIG_PARAMS;
  const { mnemonic, passphrase, accountsBalance, ...hdAccountRest } = accounts;
  return {
    ...defaultHdAccountRest,
    ...hdAccountRest,
    mnemonic: resolveConfigurationVariable(mnemonic ?? defaultMnemonic),
    accountsBalance: BigInt(accountsBalance ?? defaultAccountsBalance),
    passphrase: resolveConfigurationVariable(passphrase ?? defaultPassphrase),
  };
}

*#getTransitiveDependencies(
  root: ResolvedFile,
  dependencyGraph: DependencyGraph,
  visited = new Set<ResolvedFile>([root]),
): Generator<{
  fsPath: string[];
  versionPragmasPath: string[][];
  dependency: ResolvedFile;
}> {
  for (const dependency of dependencyGraph.getDependencies(root)) {
    const file = dependency.file;

    if (visited.has(file)) {
      continue;
    }

    visited = new Set([...visited, file]);

    yield {
      fsPath: [file.fsPath],
      versionPragmasPath: [file.content.versionPragmas],
      dependency: file,
    };

    for (const transitive of this.#getTransitiveDependencies(
      file,
      dependencyGraph,
      visited,
    )) {
      yield {
        fsPath: [file.fsPath, ...transitive.fsPath],
        versionPragmasPath: [
          file.content.versionPragmas,
          ...transitive.versionPragmasPath,
        ],
        dependency: transitive.dependency,
      };
    }
  }
}

function validateRegisteredCompilerTypes(
  resolvedConfig: HardhatConfig,
): HardhatConfigValidationError[] {
  const errors: HardhatConfigValidationError[] = [];
  const registered = new Set(resolvedConfig.solidity.registeredCompilerTypes);

  for (const [profileName, profile] of Object.entries(
    resolvedConfig.solidity.profiles,
  )) {
    for (const [i, compiler] of profile.compilers.entries()) {
      const type = compiler.type ?? "solc";
      if (!registered.has(type)) {
        errors.push({
          path: ["solidity", "profiles", profileName, "compilers", i, "type"],
          message: `Unknown compiler type "${type}". Registered types: ${[...registered].join(", ")}`,
        });
      }
    }
    for (const [sourceName, override] of Object.entries(profile.overrides)) {
      const type = override.type ?? "solc";
      if (!registered.has(type)) {
        errors.push({
          path: [
            "solidity",
            "profiles",
            profileName,
            "overrides",
            sourceName,
            "type",
          ],
          message: `Unknown compiler type "${type}". Registered types: ${[...registered].join(", ")}`,
        });
      }
    }
  }

  return errors;
}

function resolveBuildProfileConfig(
  solidityConfig:
    | SingleVersionSolidityUserConfig
    | MultiVersionSolidityUserConfig,
  production: boolean = false,
  toolVersionsInBuildInfo?: boolean,
): SolidityBuildProfileConfig {
  if ("version" in solidityConfig) {
    return {
      compilers: [resolveSolidityCompilerConfig(solidityConfig, production)],
      overrides: {},
      isolated: solidityConfig.isolated ?? production,
      preferWasm: solidityConfig.preferWasm ?? false,
      toolVersionsInBuildInfo: toolVersionsInBuildInfo ?? production,
    };
  }

  return {
    compilers: solidityConfig.compilers.map((compiler) =>
      resolveSolidityCompilerConfig(compiler, production),
    ),
    overrides: Object.fromEntries(
      Object.entries(solidityConfig.overrides ?? {}).map(
        ([userSourceName, override]) => [
          userSourceName,
          resolveSolidityCompilerConfig(override, production),
        ],
      ),
    ),
    isolated: solidityConfig.isolated ?? production,
    preferWasm: solidityConfig.preferWasm ?? false,
    toolVersionsInBuildInfo: toolVersionsInBuildInfo ?? production,
  };
}

function overwriteAddressableFunction(
  functionName: Methods,
  readableName: string,
  readableNegativeName: string,
  _super: (...args: any[]) => any,
  chaiUtils: Chai.ChaiUtils,
) {
  return function (this: Chai.AssertionStatic, ...args: any[]) {
    const [actualArg, message] = args;
    const expectedFlag = chaiUtils.flag(this, "object");

    if (message !== undefined) {
      chaiUtils.flag(this, "message", message);
    }

    const actual = tryGetAddressSync(actualArg);
    const expected = tryGetAddressSync(expectedFlag);
    if (
      functionName === "eq" &&
      expected !== undefined &&
      actual !== undefined
    ) {
      this.assert(
        expected === actual,
        `expected '${expected}' to ${readableName} '${actual}'.`,
        `expected '${expected}' to ${readableNegativeName} '${actual}'.`,
        actual.toString(),
        expected.toString(),
      );
    } else {
      _super.apply(this, args);
    }
  };
}

function overwriteBigNumberCloseTo(
  _super: (...args: any[]) => any,
  chaiUtils: Chai.ChaiUtils,
) {
  return function (this: Chai.AssertionStatic, ...args: any[]) {
    const [actualArg, deltaArg] = args;
    const expectedFlag = chaiUtils.flag(this, "object");

    if (
      isBigInt(expectedFlag) ||
      isBigInt(actualArg) ||
      isBigInt(deltaArg) ||
      typeof actualArg === "number"
    ) {
      if (deltaArg === undefined) {
        // eslint-disable-next-line no-restricted-syntax -- keep the original chai error structure
        throw new AssertionError(
          "the arguments to closeTo or approximately must be numbers, and a delta is required",
        );
      }

      const expected = toBigInt(expectedFlag);
      const actual = toBigInt(actualArg);
      const delta = toBigInt(deltaArg);

      function abs(i: bigint): bigint {
        return i < 0 ? BigInt(-1) * i : i;
      }

      this.assert(
        abs(expected - actual) <= delta,
        `expected ${expected} to be close to ${actual} +/- ${delta}`,
        `expected ${expected} not to be close to ${actual} +/- ${delta}`,
        expected,
        `A number between ${actual - delta} and ${actual + delta}`,
      );
    } else {
      _super.apply(this, args);
    }
  };
}

function supportHexEqual(Assertion: Chai.AssertionStatic): void {
  Assertion.addMethod("hexEqual", function (this: any, other: string) {
    const subject = this._obj;
    const isNegated = this.__flags.negate === true;

    // check that both values are proper hex strings
    const isHex = (a: string) => /^0x[0-9a-fA-F]*$/.test(a);
    for (const element of [subject, other]) {
      if (!isHex(element)) {
        this.assert(
          isNegated, // trick to make this assertion always fail
          `Expected "${subject}" to be a hex string equal to "${other}", but "${element}" is not a valid hex string`,
          `Expected "${subject}" not to be a hex string equal to "${other}", but "${element}" is not a valid hex string`,
        );
      }
    }

    // compare values
    const extractNumeric = (hex: string) => hex.replace(/^0x0*/, "");
    this.assert(
      extractNumeric(subject.toLowerCase()) ===
        extractNumeric(other.toLowerCase()),
      `Expected "${subject}" to be a hex string equal to "${other}"`,
      `Expected "${subject}" NOT to be a hex string equal to "${other}", but it was`,
      `Hex string representing the same number as ${other}`,
      subject,
    );
  });
}

function supportProperHex(Assertion: Chai.AssertionStatic): void {
  Assertion.addMethod("properHex", function (this: any, length: number) {
    const subject = this._obj;
    const isNegated = this.__flags.negate === true;

    const isHex = (a: string) => /^0x[0-9a-fA-F]*$/.test(a);
    if (!isHex(subject)) {
      this.assert(
        isNegated, // trick to make this assertion always fail
        `Expected "${subject}" to be a proper hex string, but it contains invalid (non-hex) characters`,
        `Expected "${subject}" NOT to be a proper hex string, but it contains only valid hex characters`,
      );
    }

    this.assert(
      subject.length === length + 2,
      `Expected "${subject}" to be a hex string of length ${
        length + 2
      } (the provided ${length} plus 2 more for the "0x" prefix), but its length is ${
        subject.length
      }`,
      `Expected "${subject}" NOT to be a hex string of length ${
        length + 2
      } (the provided ${length} plus 2 more for the "0x" prefix), but its length is ${
        subject.length
      }`,
    );
  });
}

function buildReplayTransactionRequest(
  tx: TransactionResponse,
  blockNumber: number,
): TransactionRequest {
  const request: TransactionRequest = {
    blockTag: blockNumber,
    chainId: tx.chainId,
    data: tx.data,
    from: tx.from,
    gasLimit: tx.gasLimit,
    nonce: tx.nonce,
    to: tx.to ?? undefined,
    type: tx.type,
    value: tx.value,
  };

  if (isDefined(tx.maxFeePerGas) || isDefined(tx.maxPriorityFeePerGas)) {
    request.maxFeePerGas = tx.maxFeePerGas ?? undefined;
    request.maxPriorityFeePerGas = tx.maxPriorityFeePerGas ?? undefined;
  } else if (isDefined(tx.gasPrice)) {
    request.gasPrice = tx.gasPrice;
  }

  if (isDefined(tx.accessList)) {
    request.accessList = tx.accessList;
  }

  if (isDefined(tx.maxFeePerBlobGas)) {
    request.maxFeePerBlobGas = tx.maxFeePerBlobGas;
  }

  if (isDefined(tx.blobVersionedHashes)) {
    request.blobVersionedHashes = tx.blobVersionedHashes;
  }

  if (isDefined(tx.authorizationList)) {
    request.authorizationList = tx.authorizationList;
  }

  return request;
}

function supportWithArgs(
  Assertion: Chai.AssertionStatic,
  chaiUtils: Chai.ChaiUtils,
): void {
  Assertion.addMethod("withArgs", function (this: any, ...expectedArgs: any[]) {
    const { emitCalled } = validateInput.call(this, chaiUtils);

    // Resolve arguments to their canonical form:
    // - Addressable → address
    const resolveArgument = (arg: any) =>
      isAddressable(arg) ? arg.getAddress() : arg;

    const onSuccess = (resolvedExpectedArgs: any[]) => {
      if (emitCalled) {
        return emitWithArgs(
          this,
          Assertion,
          chaiUtils,
          resolvedExpectedArgs,
          onSuccess,
        );
      } else {
        return revertedWithCustomErrorWithArgs(
          this,
          Assertion,
          chaiUtils,
          resolvedExpectedArgs,
          onSuccess,
        );
      }
    };

    const promise = (this.then === undefined ? Promise.resolve() : this)
      .then(() => Promise.all(expectedArgs.map(resolveArgument)))
      .then(onSuccess);

    this.then = promise.then.bind(promise);
    this.catch = promise.catch.bind(promise);
    return this;
  });
}

function validateInput(
  this: any,
  chaiUtils: Chai.ChaiUtils,
): { emitCalled: boolean } {
  try {
    if (Boolean(this.__flags.negate)) {
      chaiAssert.fail("Do not combine .not. with .withArgs()");
    }

    const emitCalled = chaiUtils.flag(this, EMIT_CALLED) === true;

    const revertedWithCustomErrorCalled =
      chaiUtils.flag(this, REVERTED_WITH_CUSTOM_ERROR_CALLED) === true;

    if (!emitCalled && !revertedWithCustomErrorCalled) {
      chaiAssert.fail(
        "withArgs can only be used in combination with a previous .emit or .revertedWithCustomError assertion",
      );
    }

    if (emitCalled && revertedWithCustomErrorCalled) {
      chaiAssert.fail(
        "withArgs called with both .emit and .revertedWithCustomError, but these assertions cannot be combined",
      );
    }

    return { emitCalled };
  } catch (e) {
    // signal that validation failed to allow the matchers to finish early
    chaiUtils.flag(this, ASSERTION_ABORTED, true);

    // discard subject since it could potentially be a rejected promise
    Promise.resolve(this._obj).catch(() => {});

    throw e;
  }
}

